{
  "summary": "This paper proposes lightweight embedding-based out-of-distribution (OOD) detection methods for conditional language models (CLMs) using Gaussian modeling of input and output embeddings, combined with a Relative Mahalanobis Distance score and a logistic regression classifier. It demonstrates that these methods outperform perplexity and other baselines on summarization and translation tasks, and introduces a selective generation framework that combines OOD scores with perplexity to improve quality prediction and enable abstention from low-quality outputs. The approach is computationally efficient, requires no separate detection models, and is validated with both automatic and human evaluations.",
  "strengths": [
    {
      "point": "Novel embedding-based OOD detection method tailored for CLMs",
      "evidence": "The paper introduces OOD scores derived from input and output embeddings with Gaussian modeling and Relative Mahalanobis Distance, outperforming perplexity and other baselines on summarization and translation tasks."
    },
    {
      "point": "Selective generation framework combining OOD scores with perplexity",
      "evidence": "Combining OOD detection scores with perplexity improves correlation with human quality ratings and BLEURT scores, enabling better selective generation as shown by Quality vs Abstention curves."
    },
    {
      "point": "Computational efficiency and practical applicability",
      "evidence": "The proposed methods require negligible additional computation, no separate detection models, and do not rely on ensembling or multiple forward passes."
    },
    {
      "point": "Comprehensive evaluation including human quality ratings",
      "evidence": "Experiments cover near- and far-OOD datasets in summarization and translation, with human evaluation for summarization quality supporting the selective generation claims."
    },
    {
      "point": "Insightful analysis of dataset overlap and OOD detection challenges",
      "evidence": "The paper analyzes how overlap between in-domain and background data affects detection performance, explaining low OOD detection on certain subsets."
    }
  ],
  "weaknesses": [
    {
      "point": "Lack of empirical comparison to recent neural OOD detection methods for generative models",
      "evidence": "The paper omits comparisons to likelihood ratio methods, energy-based scores, contrastive learning approaches, and uncertainty estimation methods like MC dropout or deep ensembles."
    },
    {
      "point": "Limited justification and analysis of Gaussian assumption for embeddings",
      "evidence": "No empirical tests or theoretical motivation are provided to support modeling embeddings as Gaussian; alternative density estimators are not explored."
    },
    {
      "point": "Simple averaging of hidden states may discard important sequential and positional information",
      "evidence": "The method pools embeddings by averaging token-level hidden states without exploring attention-weighted pooling, CLS tokens, or layer-wise embeddings."
    },
    {
      "point": "No ablation on individual contributions of input vs output embeddings",
      "evidence": "The paper does not analyze whether input or output embeddings alone suffice or how their combination affects performance."
    },
    {
      "point": "Evaluation limited to summarization and translation with modest-sized models",
      "evidence": "Experiments use PEGASUS and Transformer base models; claims of task-agnosticism and applicability to decoder-only models remain untested."
    },
    {
      "point": "No statistical significance testing or confidence intervals reported",
      "evidence": "Reported AUROC and correlation improvements lack statistical validation, making it unclear if gains are robust."
    },
    {
      "point": "Sparse details on human evaluation protocol and reliability",
      "evidence": "The paper does not report annotator numbers, instructions, rating scales, or inter-annotator agreement."
    },
    {
      "point": "Reproducibility hindered by missing training and hyperparameter details",
      "evidence": "Key details for the logistic regression classifier and no mention of code or data splits release."
    },
    {
      "point": "Insufficient clarity on key concepts like Relative Mahalanobis Distance and selective generation implementation",
      "evidence": "No formal equations or pseudocode are provided for RMD or abstention mechanisms."
    },
    {
      "point": "Limited discussion of model calibration, abstention trade-offs, and deployment considerations",
      "evidence": "No analysis of how OOD scores relate to calibration or safety guarantees; runtime overhead and integration complexity are not quantified."
    }
  ],
  "questions": [
    {
      "question": "How does the proposed embedding-based OOD detection compare empirically to recent neural uncertainty estimation and OOD detection methods for generative models?",
      "motivation": "Understanding relative performance and computational trade-offs is critical for assessing practical adoption."
    },
    {
      "question": "Does modeling embeddings with Gaussian distributions adequately capture their true distribution, or would more flexible density estimators improve detection?",
      "motivation": "Validating this assumption affects the robustness and generalizability of the method."
    },
    {
      "question": "How sensitive is the method to the choice and domain overlap of the background dataset used for Gaussian fitting?",
      "motivation": "Background data selection impacts detection accuracy and deployment feasibility."
    },
    {
      "question": "Can the method and selective generation framework be effectively applied to larger, decoder-only models and other generation tasks beyond summarization and translation?",
      "motivation": "Empirical validation on diverse models and tasks is necessary to support claims of generality."
    },
    {
      "question": "What are the practical implications of abstention rates on user experience and downstream applications, and how can abstention thresholds be optimally chosen?",
      "motivation": "Balancing coverage and safety is key for real-world deployment."
    }
  ],
  "scores": {
    "correctness": 3,
    "novelty": 3,
    "recommendation": "borderline",
    "confidence": 3
  }
}
